import type { SavedObjectsType } from '@kbn/core/server';
import { SAVED_VIEW_SO_TYPE } from '../../common';

/**
 * `threat-intelligence-saved-view` saved-object type.
 *
 * Stores the dashboard filter state (regions, categories, time range) as a
 * shareable pointer. The id is generated by the saved-objects client; the
 * object is scoped to a single space by default (`multiple-isolated`) and
 * can be shared to other spaces via the standard Spaces UI.
 *
 * The type is HTTP-visible (no `hiddenFromHttpApis: true`) but writes still
 * go through the plugin's internal routes so we can enforce shape + size
 * limits before saving.
 */
export const SavedViewType: SavedObjectsType = {
  name: SAVED_VIEW_SO_TYPE,
  hidden: false,
  namespaceType: 'multiple-isolated',
  mappings: {
    dynamic: false,
    properties: {
      name: { type: 'keyword' },
      description: { type: 'text' },
      filters: {
        properties: {
          regions: { type: 'keyword' },
          categories: { type: 'keyword' },
          time_range: {
            properties: {
              from: { type: 'date' },
              to: { type: 'date' },
            },
          },
        },
      },
      created_at: { type: 'date' },
      updated_at: { type: 'date' },
      owner: { type: 'keyword' },
    },
  },
  management: {
    importableAndExportable: true,
    visibleInManagement: true,
    defaultSearchField: 'name',
    getTitle: (so) => {
      const name = (so.attributes as { name?: string }).name;
      return name ? `Threat Intelligence view: ${name}` : 'Threat Intelligence saved view';
    },
  },
};
